-- Create simulation chat, create/get group (trace_id auto-generated), and link via junction tables in a single transaction
-- Converted to PostgreSQL function
-- Note: trace_id is automatically generated by database default (gen_trace_id()) and returned from groups.trace_id
-- Drop function if exists (handles signature variations)
DO $$
DECLARE
    r RECORD;
BEGIN
    FOR r IN 
        SELECT oidvectortypes(proargtypes) as sig 
        FROM pg_proc 
        WHERE proname = 'api_create_simulation_chat_v4'
          AND pronamespace = (SELECT oid FROM pg_namespace WHERE nspname = 'public')
    LOOP
        EXECUTE format('DROP FUNCTION IF EXISTS api_create_simulation_chat_v4(%s)', r.sig);
    END LOOP;
END $$;

-- Recreate function
CREATE OR REPLACE FUNCTION api_create_simulation_chat_v4(
    created_at timestamptz,
    title text,
    scenario_id uuid,
    attempt_id uuid,
    completed boolean
)
RETURNS TABLE (
    id uuid,
    created_at timestamptz,
    updated_at timestamptz,
    title text,
    scenario_id uuid,
    attempt_id uuid,
    completed boolean,
    trace_id text
)
LANGUAGE sql
VOLATILE
AS $$
WITH inserted_chat AS (
    INSERT INTO chat_artifact (created_at, title, scenario_id, completed, updated_at)
    VALUES (created_at, title, scenario_id, completed, NOW())
    RETURNING id, created_at, updated_at, title, scenario_id, completed
),
create_group_if_needed AS (
    INSERT INTO groups (created_at, updated_at)
    VALUES (NOW(), NOW())
    RETURNING id as group_id, trace_id
),
create_chat_group_if_needed AS (
    INSERT INTO chat_groups (chat_id, group_id, created_at, updated_at)
    SELECT ic.id, cg.group_id, ic.created_at, ic.updated_at
    FROM inserted_chat ic
    CROSS JOIN create_group_if_needed cg
    ON CONFLICT (chat_id, group_id) DO NOTHING
    RETURNING group_id
),
final_group AS (
    SELECT group_id FROM create_chat_group_if_needed
    LIMIT 1
),
inserted_junction AS (
    INSERT INTO attempt_chats (attempt_id, chat_id, created_at, updated_at)
    SELECT attempt_id, ic.id, ic.created_at, ic.updated_at
    FROM inserted_chat ic
    RETURNING chat_id, attempt_id
)
SELECT 
    ic.id,
    ic.created_at,
    ic.updated_at,
    ic.title,
    ic.scenario_id,
    ij.attempt_id,
    ic.completed,
    g.trace_id
FROM inserted_chat ic
JOIN inserted_junction ij ON ij.chat_id = ic.id
CROSS JOIN final_group fg
JOIN groups g ON g.id = fg.group_id
$$;